import React, { useState } from 'react';
import accessService from '../services/accessService';
import { useParams, useNavigate } from 'react-router-dom';
import { MapContainer, TileLayer, Marker, useMapEvents } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
function GrantAccess(){
  const { fileId } = useParams();
  const [userEmail,setUserEmail]=useState(''); const [role,setRole]=useState('read');
  const [expiry,setExpiry]=useState(''); const [location,setLocation]=useState(null); const [radius,setRadius] = useState('100');
  const navigate=useNavigate();
  const submit = async(e)=>{ e.preventDefault(); try{ await accessService.grant({ fileId, userEmail, role, expiry_time: expiry, geo_lat: location?location.lat:null, geo_lon: location?location.lng:null, geo_radius_m: radius?Number(radius):null }); alert('Granted'); navigate('/dashboard'); }catch(e){ alert('Failed'); } };
  const defaultCenter = { lat: 18.5204, lng: 73.8567 };

  // Custom marker icon for Leaflet
  const markerIcon = new L.Icon({
    iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
    iconSize: [25, 41],
    iconAnchor: [12, 41],
    popupAnchor: [1, -34],
    shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
    shadowSize: [41, 41]
  });

  // Component to handle map click and set location
  function LocationMarker() {
    useMapEvents({
      click(e) {
        setLocation({ lat: e.latlng.lat, lng: e.latlng.lng });
      }
    });
    return location ? (
      <Marker position={location} icon={markerIcon} />
    ) : null;
  }
  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-100 flex flex-col items-center p-8">
      <div className="w-full max-w-2xl bg-white rounded-2xl shadow-lg p-8">
        <h2 className="text-3xl font-bold mb-6 text-blue-700">Grant Access for File ID: {fileId}</h2>
        <form onSubmit={submit} className="space-y-6">
          <input required placeholder="User Email" value={userEmail} onChange={e=>setUserEmail(e.target.value)} className="w-full p-3 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-400"/>
          <select value={role} onChange={e=>setRole(e.target.value)} className="w-full p-3 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-400">
            <option value="read">Read</option><option value="write">Write</option><option value="download">Download</option><option value="share">Share</option>
          </select>
          <input type="datetime-local" value={expiry} onChange={e=>setExpiry(e.target.value)} className="w-full p-3 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-400"/>
          <input type="number" min="10" step="10" placeholder="Radius (meters) e.g., 50/100/200" value={radius} onChange={e=>setRadius(e.target.value)} className="w-full p-3 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-400"/>
          <div className="mb-4" style={{ height: '300px', width: '100%' }}>
            <MapContainer center={defaultCenter} zoom={10} style={{ height: '100%', width: '100%' }}>
              <TileLayer
                url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                attribution="&copy; OpenStreetMap contributors"
              />
              <LocationMarker />
            </MapContainer>
          </div>
          <button className="bg-green-600 text-white px-6 py-3 rounded-lg shadow hover:bg-green-700 transition w-full">Grant Access</button>
        </form>
      </div>
    </div>
  );
}
export default GrantAccess;
